#include <compare>
#include <iostream>
#include <string>
#include <cctype>
#include <algorithm>

struct Version {
    int major, minor, patch;
    auto operator<=>(const Version&) const = default;
};

struct CaseInsensitiveString {
    std::string s;

    std::weak_ordering operator<=>(const CaseInsensitiveString& other) const {
        auto lower = [](unsigned char c){ return std::tolower(c); };
        for (size_t i = 0; i < std::min(s.size(), other.s.size()); ++i) {
            if (auto c = lower(s[i]) <=> lower(other.s[i]); c != 0) return c;
        }
        return s.size() <=> other.s.size();
    }
    bool operator==(const CaseInsensitiveString& other) const {
        return (*this <=> other) == 0;
    }
};

int main() {
    Version v1{1, 2, 3}, v2{1, 3, 0}, v3{1, 2, 3};

    std::cout << std::boolalpha;
    std::cout << "v1 < v2: " << (v1 < v2) << '\n';
    std::cout << "v1 > v2: " << (v1 > v2) << '\n';
    std::cout << "v1 == v3: " << (v1 == v3) << '\n';
    std::cout << "v1 <= v3: " << (v1 <= v3) << '\n';

    CaseInsensitiveString a{"Hello"}, b{"hello"}, c{"World"};
    std::cout << "Hello == hello: " << (a == b) << '\n';
    std::cout << "Hello < World: " << (a < c) << '\n';
}

#include <compare>
#include <iostream>
#include <vector>
#include <algorithm>
#include <string>
#include <limits>

struct Employee {
    std::string name;
    int salary;

    // Order by salary only; same salary = equivalent but distinguishable
    std::weak_ordering operator<=>(const Employee& other) const {
        return salary <=> other.salary;
    }
    bool operator==(const Employee& other) const {
        return salary == other.salary;
    }
};

void show_categories() {
    auto si = (1 <=> 2);  // strong_ordering::less

    std::weak_ordering w = si;
    std::partial_ordering p = si;

    std::cout << "int <=> yields strong_ordering\n";
    std::cout << "converts to weak:    " << (w == std::weak_ordering::less ? "less" : "other") << '\n';
    std::cout << "converts to partial: " << (p == std::partial_ordering::less ? "less" : "other") << '\n';

    double nan = std::numeric_limits<double>::quiet_NaN();
    auto fc = nan <=> 1.0;
    std::cout << "NaN <=> 1.0 unordered: " << (fc == std::partial_ordering::unordered) << '\n';
}

int main() {
    std::cout << std::boolalpha;
    show_categories();

    std::vector<Employee> team = {
        {"Alice", 90000}, {"Bob", 75000}, {"Charlie", 90000}
    };
    std::sort(team.begin(), team.end());
    std::cout << "\nSorted by salary:\n";
    for (auto& e : team) std::cout << "  " << e.name << ": " << e.salary << '\n';
}
